export const AGENT_PROTOCOL_VERSION = "overseer/v1";
export const AGENT_HANDOFF_TARGETS = [
	"@overseer",
	"@product-architect",
	"@planner",
	"@developer-tester",
	"@quality",
	"human_review_required",
] as const;

export type AgentTaskStatus = "in_progress" | "done";
export type AgentHandoffTarget = (typeof AGENT_HANDOFF_TARGETS)[number];

export interface RunShellAction {
	type: "run_shell";
	command: string;
}

export interface PersistWorkAction {
	type: "persist_work";
}

export type AgentAction = RunShellAction | PersistWorkAction;

export interface AgentProtocolResponse {
	version: typeof AGENT_PROTOCOL_VERSION;
	plan: string[];
	next_step: string;
	actions: AgentAction[];
	task_status: AgentTaskStatus;
	final_response?: string;
	github_comment?: string;
	handoff_to?: AgentHandoffTarget;
}

export interface ParsedAgentProtocolResponse {
	protocol: AgentProtocolResponse;
	rawJson: string;
}

export interface ContinuationContext {
	originalTask: string;
	previousResponseJson: string;
	previousGithubComment?: string;
	actionOutput: string;
}

export const AGENT_PROTOCOL_PROMPT = `
RESPONSE PROTOCOL:
Work to this workflow on every turn:
1. Keep a concrete plan in mind.
2. Return that plan explicitly in \`plan\`.
2. State the immediate next step in \`next_step\`.
3. Either take one or more ordered actions or finish the task.
4. Observe the result and loop.
- Return exactly one JSON object and nothing else.
- Use \`"version": "${AGENT_PROTOCOL_VERSION}"\`.
- Always include \`plan\`, \`next_step\`, \`actions\`, and \`task_status\`.
- You may include \`github_comment\` as a concise markdown progress update to append to the GitHub issue thread.
- You may include \`handoff_to\` on \`"done"\` responses to make the next recipient explicit. Valid values: ${AGENT_HANDOFF_TARGETS.map((target) => `\`${target}\``).join(", ")}.
- If you need to inspect or modify the repository, respond with \`"task_status": "in_progress"\` and at least one action.
- \`actions\` is an ordered list executed sequentially by the dispatcher.
- Available actions: \`{"type":"run_shell","command":"..."}\` and \`{"type":"persist_work"}\`.
- Use \`{"type":"run_shell","command":"..."}\` for repository inspection, file edits, and verification commands.
- Use \`{"type":"persist_work"}\` only when your persona is authorized to publish repo changes and you want the dispatcher-owned persistence mechanism to commit and push your work.
- \`github_comment\` is for in-progress status only. Do not put delegation or the final handoff there.
- If you set \`handoff_to\`, the dispatcher will append the standardized \`Next step: ...\` line when it posts your final GitHub comment.
- If the task is complete, respond with \`"task_status": "done"\`, \`"actions": []\`, and \`final_response\` containing the concise human-facing summary that should be posted back to GitHub.
- Do not use \`[RUN:command]\`, markdown fences, or prose outside the JSON object.

Example in-progress response:
{"version":"${AGENT_PROTOCOL_VERSION}","plan":["Inspect the relevant files.","Make the minimal required change.","Run targeted verification."],"next_step":"Read the relevant files before editing.","actions":[{"type":"run_shell","command":"cd /project && ls -la"},{"type":"run_shell","command":"cd /project && cat WORKFLOW.md"}],"task_status":"in_progress","github_comment":"Started work and am inspecting the relevant files."}

Example done response:
{"version":"${AGENT_PROTOCOL_VERSION}","plan":["Inspect the relevant files.","Make the minimal required change.","Run targeted verification."],"next_step":"Return control to the dispatcher.","actions":[],"task_status":"done","handoff_to":"@planner","final_response":"Identified the relevant implementation touchpoints and prepared the planner handoff."}
`;

export function buildProtocolRepairMessage(
	error: string,
	previousResponse: string,
): string {
	return [
		`Your previous response was invalid: ${error}`,
		`Return exactly one JSON object matching protocol "${AGENT_PROTOCOL_VERSION}".`,
		"Do not use markdown fences or any prose outside the JSON object.",
		"Previous response:",
		previousResponse,
	].join("\n\n");
}

export function buildContinuationMessage({
	originalTask,
	previousResponseJson,
	previousGithubComment,
	actionOutput,
}: ContinuationContext): string {
	return [
		"ORIGINAL TASK:",
		originalTask,
		"",
		"MOST RECENT STRUCTURED RESPONSE:",
		previousResponseJson,
		"",
		...(previousGithubComment
			? ["MOST RECENT GITHUB STATUS COMMENT:", previousGithubComment, ""]
			: []),
		"LATEST ACTION OUTPUT:",
		actionOutput,
		"",
		"Continue the same task. Do not restart or reinterpret the assignment.",
		"Use the original task and your most recent structured response to decide the next step.",
		`Continue the task using protocol "${AGENT_PROTOCOL_VERSION}".`,
		"Return exactly one JSON object.",
	].join("\n");
}

export function parseAgentProtocolResponse(
	responseText: string,
): ParsedAgentProtocolResponse {
	const rawJson = extractJsonObject(responseText);
	let parsed: unknown;

	try {
		parsed = JSON.parse(rawJson);
	} catch (error) {
		throw new Error(
			`response was not valid JSON: ${
				error instanceof Error ? error.message : String(error)
			}`,
		);
	}

	if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) {
		throw new Error("top-level JSON value must be an object");
	}

	const record = parsed as Record<string, unknown>;
	const version = requireNonEmptyString(record.version, "version");
	if (version !== AGENT_PROTOCOL_VERSION) {
		throw new Error(
			`version must be "${AGENT_PROTOCOL_VERSION}", received "${version}"`,
		);
	}

	const nextStep = requireNonEmptyString(record.next_step, "next_step");
	const plan = parseRequiredPlan(record.plan);
	const taskStatus = parseTaskStatus(record.task_status);
	const actions = parseActions(record.actions);
	const finalResponse = parseOptionalNonEmptyString(
		record.final_response,
		"final_response",
	);
	const githubComment = parseOptionalNonEmptyString(
		record.github_comment,
		"github_comment",
	);
	const handoffTo = parseOptionalHandoffTarget(record.handoff_to);

	if (taskStatus === "in_progress" && actions.length === 0) {
		throw new Error(
			'task_status "in_progress" requires at least one action in actions[]',
		);
	}
	if (taskStatus !== "done" && handoffTo) {
		throw new Error('handoff_to is only valid when task_status is "done"');
	}

	if (taskStatus === "done") {
		if (actions.length !== 0) {
			throw new Error('task_status "done" requires actions to be empty');
		}
		if (!finalResponse) {
			throw new Error(
				'task_status "done" requires a non-empty final_response string',
			);
		}
	}

	return {
		rawJson,
		protocol: {
			version: AGENT_PROTOCOL_VERSION,
			plan,
			next_step: nextStep,
			actions,
			task_status: taskStatus,
			final_response: finalResponse,
			github_comment: githubComment,
			handoff_to: handoffTo,
		},
	};
}

function extractJsonObject(responseText: string): string {
	const trimmed = responseText.trim();
	if (!trimmed) {
		throw new Error("response was empty");
	}

	const fencedMatch = trimmed.match(/^```(?:json)?\s*([\s\S]*?)\s*```$/i);
	if (fencedMatch?.[1]) {
		return fencedMatch[1].trim();
	}

	if (trimmed.startsWith("{") && trimmed.endsWith("}")) {
		return trimmed;
	}

	const embeddedObject = extractBalancedObject(trimmed);
	if (embeddedObject) {
		return embeddedObject;
	}

	throw new Error("could not find a JSON object in the response");
}

function extractBalancedObject(text: string): string | null {
	let startIndex = -1;
	let depth = 0;
	let inString = false;
	let isEscaped = false;

	for (let index = 0; index < text.length; index++) {
		const char = text[index];
		if (!char) {
			continue;
		}

		if (isEscaped) {
			isEscaped = false;
			continue;
		}

		if (char === "\\") {
			isEscaped = true;
			continue;
		}

		if (char === '"') {
			inString = !inString;
			continue;
		}

		if (inString) {
			continue;
		}

		if (char === "{") {
			if (depth === 0) {
				startIndex = index;
			}
			depth++;
			continue;
		}

		if (char === "}") {
			if (depth === 0) {
				continue;
			}
			depth--;
			if (depth === 0 && startIndex >= 0) {
				return text.slice(startIndex, index + 1);
			}
		}
	}

	return null;
}

function requireNonEmptyString(value: unknown, fieldName: string): string {
	if (typeof value !== "string" || value.trim().length === 0) {
		throw new Error(`${fieldName} must be a non-empty string`);
	}
	return value.trim();
}

function parseOptionalNonEmptyString(
	value: unknown,
	fieldName: string,
): string | undefined {
	if (value === undefined) {
		return undefined;
	}
	return requireNonEmptyString(value, fieldName);
}

function parseTaskStatus(value: unknown): AgentTaskStatus {
	if (value === "in_progress" || value === "done") {
		return value;
	}
	throw new Error('task_status must be either "in_progress" or "done"');
}

function parseOptionalHandoffTarget(
	value: unknown,
): AgentHandoffTarget | undefined {
	if (value === undefined) {
		return undefined;
	}
	const handoffTo = requireNonEmptyString(value, "handoff_to");
	if (!(AGENT_HANDOFF_TARGETS as readonly string[]).includes(handoffTo)) {
		throw new Error(
			`handoff_to must be one of: ${AGENT_HANDOFF_TARGETS.join(", ")}`,
		);
	}
	return handoffTo as AgentHandoffTarget;
}

function parseActions(value: unknown): AgentAction[] {
	if (!Array.isArray(value)) {
		throw new Error("actions must be an array");
	}

	return value.map((action, index) => parseAction(action, index));
}

function parseAction(value: unknown, index: number): AgentAction {
	if (!value || typeof value !== "object" || Array.isArray(value)) {
		throw new Error(`actions[${index}] must be an object`);
	}

	const record = value as Record<string, unknown>;
	const type = requireNonEmptyString(record.type, `actions[${index}].type`);
	if (type === "run_shell") {
		return {
			type: "run_shell",
			command: requireNonEmptyString(
				record.command,
				`actions[${index}].command`,
			),
		};
	}

	if (type === "persist_work") {
		return {
			type: "persist_work",
		};
	}

	throw new Error(
		`actions[${index}].type must be "run_shell" or "persist_work"`,
	);
}

function parseRequiredPlan(value: unknown): string[] {
	if (!Array.isArray(value)) {
		throw new Error("plan must be an array of strings");
	}
	if (value.length === 0) {
		throw new Error("plan must contain at least one step");
	}

	return value.map((entry, index) =>
		requireNonEmptyString(entry, `plan[${index}]`),
	);
}
import { existsSync, readFileSync } from "node:fs";
import { resolve } from "node:path";
import type { Content } from "@google/generative-ai";
import {
	type AgentHandoffTarget,
	buildContinuationMessage,
	buildProtocolRepairMessage,
	type ParsedAgentProtocolResponse,
	parseAgentProtocolResponse,
} from "./agent_protocol.js";
import { prependStatusUpdateSentinel } from "./comment_markers.js";
import type { GeminiService } from "./gemini.js";
import type { PersistWorkResult } from "./persistence.js";
import { ShellService } from "./shell.js";
import { logTrace, textStats } from "./trace.js";

export interface IterationResult {
	finalResponse: string;
	handoffTo?: AgentHandoffTarget;
	log: string;
}

export interface AgentRunnerOptions {
	persistWork?: () => Promise<PersistWorkResult>;
	appendGithubComment?: (markdown: string) => Promise<void>;
	requireDoneHandoff?: boolean;
	modelName?: string;
	promptDefinition?: {
		botId: string;
		displayName: string;
		llm: {
			provider: string;
			model: string;
		};
		promptFiles: string[];
		promptFileContents: Record<
			string,
			{
				stats: ReturnType<typeof textStats>;
				content: string;
			}
		>;
		concatenatedPrompt: {
			stats: ReturnType<typeof textStats>;
			content: string;
		};
	};
}

export class AgentRunner {
	private shell: ShellService;
	private sessionLog: string = "";

	constructor(shell: ShellService = new ShellService()) {
		this.shell = shell;
	}

	async runAutonomousLoop(
		gemini: GeminiService,
		systemInstruction: string,
		initialMessage: string,
		maxIterations: number = 50,
		options: AgentRunnerOptions = {},
	): Promise<IterationResult> {
		const repositoryGuidance = this.loadRepositoryGuidance();
		logTrace("agent.loop.start", {
			maxIterations,
			modelName: options.modelName,
			systemInstruction: textStats(systemInstruction),
			systemInstructionRaw: systemInstruction,
			initialMessage: textStats(initialMessage),
			initialMessageRaw: initialMessage,
			promptDefinition: options.promptDefinition,
			repositoryGuidancePath: repositoryGuidance.path,
			repositoryGuidance: repositoryGuidance.content
				? textStats(repositoryGuidance.content)
				: undefined,
			repositoryGuidanceRaw: repositoryGuidance.content,
			repositoryGuidanceHistory: repositoryGuidance.history,
		});
		const chat = gemini.startChat(
			systemInstruction,
			repositoryGuidance.history,
			options.modelName,
		);
		const originalTask = initialMessage;
		let currentMessage = initialMessage;
		let iteration = 0;

		while (iteration < maxIterations) {
			iteration++;
			this.log(`\n=== ITERATION ${iteration} ===\n`);
			this.log(`AGENT INPUT: ${currentMessage}\n`);
			logTrace("agent.iteration.begin", {
				iteration,
				input: textStats(currentMessage),
				inputRaw: currentMessage,
			});

			const sendStartedAt = Date.now();
			const result = await chat.sendMessage(currentMessage);
			const responseText = result.text;
			logTrace("agent.iteration.response", {
				iteration,
				durationMs: Date.now() - sendStartedAt,
				response: textStats(responseText),
				responseRaw: responseText,
				responseIsEmpty: responseText.trim().length === 0,
			});

			this.log(`AGENT RESPONSE: ${responseText}\n`);

			let parsedResponse: ParsedAgentProtocolResponse;
			try {
				parsedResponse = parseAgentProtocolResponse(responseText);
			} catch (error) {
				logTrace("agent.iteration.protocolError", {
					iteration,
					error: error instanceof Error ? error.message : String(error),
				});
				currentMessage = buildProtocolRepairMessage(
					error instanceof Error ? error.message : String(error),
					responseText,
				);
				continue;
			}

			logTrace("agent.iteration.protocol", {
				iteration,
				plan: parsedResponse.protocol.plan,
				taskStatus: parsedResponse.protocol.task_status,
				nextStep: parsedResponse.protocol.next_step,
				actionCount: parsedResponse.protocol.actions.length,
				githubComment: textStats(parsedResponse.protocol.github_comment || ""),
				githubCommentRaw: parsedResponse.protocol.github_comment || "",
				finalResponse: textStats(parsedResponse.protocol.final_response || ""),
				finalResponseRaw: parsedResponse.protocol.final_response || "",
				handoffTo: parsedResponse.protocol.handoff_to,
			});
			this.log(`PROTOCOL RESPONSE: ${parsedResponse.rawJson}\n`);

			if (parsedResponse.protocol.github_comment) {
				await this.appendGithubComment(
					parsedResponse.protocol.github_comment,
					options,
					iteration,
				);
			}

			if (parsedResponse.protocol.task_status === "done") {
				if (options.requireDoneHandoff && !parsedResponse.protocol.handoff_to) {
					const error =
						'task_status "done" requires a non-empty handoff_to for this persona';
					logTrace("agent.iteration.protocolError", {
						iteration,
						error,
					});
					currentMessage = buildProtocolRepairMessage(error, responseText);
					continue;
				}
				return {
					finalResponse: parsedResponse.protocol.final_response || "",
					handoffTo: parsedResponse.protocol.handoff_to,
					log: this.sessionLog,
				};
			}

			const actionOutput = await this.executeActions(
				parsedResponse.protocol.actions,
				options,
			);
			logTrace("agent.iteration.action", {
				iteration,
				actionTypes: parsedResponse.protocol.actions.map(
					(action) => action.type,
				),
				actionOutput: textStats(actionOutput),
			});
			this.log(`ACTION OUTPUT: ${actionOutput}\n`);
			currentMessage = buildContinuationMessage({
				originalTask,
				previousResponseJson: parsedResponse.rawJson,
				previousGithubComment: parsedResponse.protocol.github_comment,
				actionOutput,
			});
		}

		logTrace("agent.loop.maxIterationsReached", {
			maxIterations,
		});
		return {
			finalResponse: "ERROR: Max iterations reached without completion.",
			log: this.sessionLog,
		};
	}

	private log(text: string) {
		this.sessionLog += text;
		console.log(text);
	}

	private async executeActions(
		actions: ParsedAgentProtocolResponse["protocol"]["actions"],
		options: AgentRunnerOptions,
	): Promise<string> {
		if (actions.length === 0) {
			return "ERROR: No actions were supplied.";
		}

		const outputs: string[] = [];

		for (const action of actions) {
			if (action.type === "run_shell") {
				outputs.push(await this.shell.executeActions([action]));
				continue;
			}

			if (!options.persistWork) {
				outputs.push(
					JSON.stringify(
						{
							ok: false,
							error_code: "persist_not_available",
							message:
								'persist_work is not available for this persona. Use "run_shell" instead.',
						},
						null,
						2,
					),
				);
				continue;
			}

			const result = await options.persistWork();
			outputs.push(JSON.stringify(result, null, 2));
		}

		return outputs.join("\n");
	}

	private async appendGithubComment(
		markdown: string,
		options: AgentRunnerOptions,
		iteration: number,
	): Promise<void> {
		if (!options.appendGithubComment) {
			logTrace("agent.iteration.githubComment.skipped", {
				iteration,
				reason: "appendGithubComment not configured",
				githubComment: textStats(markdown),
				githubCommentRaw: markdown,
			});
			return;
		}

		const commentBody = prependStatusUpdateSentinel(markdown);
		await options.appendGithubComment(commentBody);
		logTrace("agent.iteration.githubComment.posted", {
			iteration,
			githubComment: textStats(markdown),
			githubCommentRaw: markdown,
			commentBody: textStats(commentBody),
			commentBodyRaw: commentBody,
		});
		this.log(`GITHUB COMMENT APPENDED: ${markdown}\n`);
	}

	private loadRepositoryGuidance(): {
		path?: string;
		content?: string;
		history: Content[];
	} {
		const agentsPath = resolve(process.cwd(), "AGENTS.md");
		if (!existsSync(agentsPath)) {
			return {
				history: [],
			};
		}

		const content = readFileSync(agentsPath, "utf8").trim();
		if (content.length === 0) {
			return {
				path: agentsPath,
				content,
				history: [],
			};
		}

		const userMessage = [
			"Repository guidance from the top-level AGENTS.md file.",
			"Follow this guidance for the rest of the task.",
			"",
			"AGENTS.md:",
			"",
			content,
		].join("\n");

		return {
			path: agentsPath,
			content,
			history: [
				{
					role: "user",
					parts: [{ text: userMessage }],
				},
