			continue;
		}

		if (inString) {
			continue;
		}

		if (char === "{") {
			if (depth === 0) {
				startIndex = index;
			}
			depth++;
			continue;
		}

		if (char === "}") {
			if (depth === 0) {
				continue;
			}
			depth--;
			if (depth === 0 && startIndex >= 0) {
				return text.slice(startIndex, index + 1);
			}
		}
	}

	return null;
}

